package com.example.knowledgecollector.boot;
import com.example.knowledgecollector.application.security.UserService;import org.springframework.beans.factory.annotation.Value;import org.springframework.boot.*;import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;import org.springframework.stereotype.Component;
@Component @ConditionalOnProperty(name="knowledge-collector.security.enabled",havingValue="true",matchIfMissing=true) public class InitialAdminInitializer implements ApplicationRunner {private final UserService users;private final String username,password;public InitialAdminInitializer(UserService users,@Value("${knowledge-collector.security.initial-admin-username:}")String username,@Value("${knowledge-collector.security.initial-admin-password:}")String password){this.users=users;this.username=username;this.password=password;}public void run(ApplicationArguments args){users.initializeAdmin(username,password);}}
